4150 /// For all PostIncLoopSets in \p Loops, first de-normalize \p Expr, then
4151 /// perform the extension/truncate and normalize again, as the normalized form
4152 /// can result in folds that are not valid in the post-inc use contexts. The
4153 /// expressions for all PostIncLoopSets must match, otherwise return nullptr.
4154 static const SCEV *
4155 getAnyExtendConsideringPostIncUses(ArrayRef<PostIncLoopSet> Loops,
4156                                    const SCEV *Expr, Type *ToTy,
4157                                    ScalarEvolution &SE) {
4158   const SCEV *Result = nullptr;
4159   for (auto &L : Loops) {
4160     auto *DenormExpr = denormalizeForPostIncUse(Expr, L, SE);
4161     const SCEV *NewDenormExpr = SE.getAnyExtendExpr(DenormExpr, ToTy);
4162     const SCEV *New = normalizeForPostIncUse(NewDenormExpr, L, SE);
4163     if (Result && New != Result)
4164       return nullptr;
4165     Result = New;
4166   }
4167 
4168   assert(Result && "failed to create expression");
4169   return Result;
4170 }
