4172 /// Generate reuse formulae from different IV types.
4173 void LSRInstance::GenerateTruncates(LSRUse &LU, unsigned LUIdx, Formula Base) {
4174   // Don't bother truncating symbolic values.
4175   if (Base.BaseGV) return;
4176 
4177   // Determine the integer type for the base formula.
4178   Type *DstTy = Base.getType();
4179   if (!DstTy) return;
4180   if (DstTy->isPointerTy())
4181     return;
4182 
4183   // It is invalid to extend a pointer type so exit early if ScaledReg or
4184   // any of the BaseRegs are pointers.
4185   if (Base.ScaledReg && Base.ScaledReg->getType()->isPointerTy())
4186     return;
4187   if (any_of(Base.BaseRegs,
4188              [](const SCEV *S) { return S->getType()->isPointerTy(); }))
4189     return;
4190 
4191   SmallVector<PostIncLoopSet> Loops;
4192   for (auto &LF : LU.Fixups)
4193     Loops.push_back(LF.PostIncLoops);
4194 
4195   for (Type *SrcTy : Types) {
4196     if (SrcTy != DstTy && TTI.isTruncateFree(SrcTy, DstTy)) {
4197       Formula F = Base;
4198 
4199       // Sometimes SCEV is able to prove zero during ext transform. It may
4200       // happen if SCEV did not do all possible transforms while creating the
4201       // initial node (maybe due to depth limitations), but it can do them while
4202       // taking ext.
4203       if (F.ScaledReg) {
4204         const SCEV *NewScaledReg =
4205             getAnyExtendConsideringPostIncUses(Loops, F.ScaledReg, SrcTy, SE);
4206         if (!NewScaledReg || NewScaledReg->isZero())
4207           continue;
4208         F.ScaledReg = NewScaledReg;
4209       }
4210       bool HasZeroBaseReg = false;
4211       for (const SCEV *&BaseReg : F.BaseRegs) {
4212         const SCEV *NewBaseReg =
4213             getAnyExtendConsideringPostIncUses(Loops, BaseReg, SrcTy, SE);
4214         if (!NewBaseReg || NewBaseReg->isZero()) {
4215           HasZeroBaseReg = true;
4216           break;
4217         }
4218         BaseReg = NewBaseReg;
4219       }
4220       if (HasZeroBaseReg)
4221         continue;
4222 
4223       // TODO: This assumes we've done basic processing on all uses and
4224       // have an idea what the register usage is.
4225       if (!F.hasRegsUsedByUsesOtherThan(LUIdx, RegUses))
4226         continue;
4227 
4228       F.canonicalize(*L);
4229       (void)InsertFormula(LU, LUIdx, F);
4230     }
4231   }
