4264 /// Look for registers which are a constant distance apart and try to form reuse
4265 /// opportunities between them.
4266 void LSRInstance::GenerateCrossUseConstantOffsets() {
4267   // Group the registers by their value without any added constant offset.
4268   using ImmMapTy = std::map<int64_t, const SCEV *>;
4269 
4270   DenseMap<const SCEV *, ImmMapTy> Map;
4271   DenseMap<const SCEV *, SmallBitVector> UsedByIndicesMap;
4272   SmallVector<const SCEV *, 8> Sequence;
4273   for (const SCEV *Use : RegUses) {
4274     const SCEV *Reg = Use; // Make a copy for ExtractImmediate to modify.
4275     int64_t Imm = ExtractImmediate(Reg, SE);
4276     auto Pair = Map.insert(std::make_pair(Reg, ImmMapTy()));
4277     if (Pair.second)
4278       Sequence.push_back(Reg);
4279     Pair.first->second.insert(std::make_pair(Imm, Use));
4280     UsedByIndicesMap[Reg] |= RegUses.getUsedByIndices(Use);
4281   }
4282 
4283   // Now examine each set of registers with the same base value. Build up
4284   // a list of work to do and do the work in a separate step so that we're
4285   // not adding formulae and register counts while we're searching.
4286   SmallVector<WorkItem, 32> WorkItems;
4287   SmallSet<std::pair<size_t, int64_t>, 32> UniqueItems;
4288   for (const SCEV *Reg : Sequence) {
4289     const ImmMapTy &Imms = Map.find(Reg)->second;
4290 
4291     // It's not worthwhile looking for reuse if there's only one offset.
4292     if (Imms.size() == 1)
4293       continue;
4294 
4295     LLVM_DEBUG(dbgs() << "Generating cross-use offsets for " << *Reg << ':';
4296                for (const auto &Entry
4297                     : Imms) dbgs()
4298                << ' ' << Entry.first;
4299                dbgs() << '\n');
4300 
4301     // Examine each offset.
4302     for (ImmMapTy::const_iterator J = Imms.begin(), JE = Imms.end();
4303          J != JE; ++J) {
4304       const SCEV *OrigReg = J->second;
4305 
4306       int64_t JImm = J->first;
4307       const SmallBitVector &UsedByIndices = RegUses.getUsedByIndices(OrigReg);
4308 
4309       if (!isa<SCEVConstant>(OrigReg) &&
4310           UsedByIndicesMap[Reg].count() == 1) {
4311         LLVM_DEBUG(dbgs() << "Skipping cross-use reuse for " << *OrigReg
4312                           << '\n');
4313         continue;
4314       }
4315 
4316       // Conservatively examine offsets between this orig reg a few selected
4317       // other orig regs.
4318       int64_t First = Imms.begin()->first;
4319       int64_t Last = std::prev(Imms.end())->first;
4320       // Compute (First + Last)  / 2 without overflow using the fact that
4321       // First + Last = 2 * (First + Last) + (First ^ Last).
4322       int64_t Avg = (First & Last) + ((First ^ Last) >> 1);
4323       // If the result is negative and First is odd and Last even (or vice versa),
4324       // we rounded towards -inf. Add 1 in that case, to round towards 0.
4325       Avg = Avg + ((First ^ Last) & ((uint64_t)Avg >> 63));
4326       ImmMapTy::const_iterator OtherImms[] = {
4327           Imms.begin(), std::prev(Imms.end()),
4328          Imms.lower_bound(Avg)};
4329       for (const auto &M : OtherImms) {
4330         if (M == J || M == JE) continue;
4331 
4332         // Compute the difference between the two.
4333         int64_t Imm = (uint64_t)JImm - M->first;
4334         for (unsigned LUIdx : UsedByIndices.set_bits())
4335           // Make a memo of this use, offset, and register tuple.
4336           if (UniqueItems.insert(std::make_pair(LUIdx, Imm)).second)
4337             WorkItems.push_back(WorkItem(LUIdx, Imm, OrigReg));
4338       }
4339     }
4340   }
4341 
4342   Map.clear();
4343   Sequence.clear();
4344   UsedByIndicesMap.clear();
4345   UniqueItems.clear();
4346 
4347   // Now iterate through the worklist and add new formulae.
4348   for (const WorkItem &WI : WorkItems) {
4349     size_t LUIdx = WI.LUIdx;
4350     LSRUse &LU = Uses[LUIdx];
4351     int64_t Imm = WI.Imm;
4352     const SCEV *OrigReg = WI.OrigReg;
4353 
4354     Type *IntTy = SE.getEffectiveSCEVType(OrigReg->getType());
4355     const SCEV *NegImmS = SE.getSCEV(ConstantInt::get(IntTy, -(uint64_t)Imm));
4356     unsigned BitWidth = SE.getTypeSizeInBits(IntTy);
4357 
4358     // TODO: Use a more targeted data structure.
4359     for (size_t L = 0, LE = LU.Formulae.size(); L != LE; ++L) {
4360       Formula F = LU.Formulae[L];
4361       // FIXME: The code for the scaled and unscaled registers looks
4362       // very similar but slightly different. Investigate if they
4363       // could be merged. That way, we would not have to unscale the
4364       // Formula.
4365       F.unscale();
4366       // Use the immediate in the scaled register.
4367       if (F.ScaledReg == OrigReg) {
4368         int64_t Offset = (uint64_t)F.BaseOffset + Imm * (uint64_t)F.Scale;
4369         // Don't create 50 + reg(-50).
4370         if (F.referencesReg(SE.getSCEV(
4371                    ConstantInt::get(IntTy, -(uint64_t)Offset))))
4372           continue;
4373         Formula NewF = F;
4374         NewF.BaseOffset = Offset;
4375         if (!isLegalUse(TTI, LU.MinOffset, LU.MaxOffset, LU.Kind, LU.AccessTy,
4376                         NewF))
4377           continue;
4378         NewF.ScaledReg = SE.getAddExpr(NegImmS, NewF.ScaledReg);
4379 
4380         // If the new scale is a constant in a register, and adding the constant
4381         // value to the immediate would produce a value closer to zero than the
4382         // immediate itself, then the formula isn't worthwhile.
4383         if (const SCEVConstant *C = dyn_cast<SCEVConstant>(NewF.ScaledReg))
4384           if (C->getValue()->isNegative() != (NewF.BaseOffset < 0) &&
4385               (C->getAPInt().abs() * APInt(BitWidth, F.Scale))
4386                   .ule(std::abs(NewF.BaseOffset)))
4387             continue;
4388 
4389         // OK, looks good.
4390         NewF.canonicalize(*this->L);
4391         (void)InsertFormula(LU, LUIdx, NewF);
4392       } else {
4393         // Use the immediate in a base register.
4394         for (size_t N = 0, NE = F.BaseRegs.size(); N != NE; ++N) {
4395           const SCEV *BaseReg = F.BaseRegs[N];
4396           if (BaseReg != OrigReg)
4397             continue;
4398           Formula NewF = F;
4399           NewF.BaseOffset = (uint64_t)NewF.BaseOffset + Imm;
